<?php
declare(strict_types=1);
/**
 * HO v2 codegen — reads schema/business.schema.json, generates:
 *   1. migrations/002_business_profile.sql   (DDL)
 *   2. generated/research_spec.json           (JSON skeleton injected into prompts)
 *   3. src/Import/Validator.php               (enum/clamp/null-rule validation)
 *   4. src/Domain/Business.php                (typed canonical object)
 *
 * NEVER hand-edit the generated files. Edit the schema, re-run this.
 * Usage: php bin/codegen.php
 */

$root   = dirname(__DIR__);
$schema = json_decode(file_get_contents($root . '/schema/business.schema.json'), true, 512, JSON_THROW_ON_ERROR);
$fields = [];
foreach ($schema['groups'] as $group => $defs) {
    foreach ($defs as $name => $def) {
        $def['group'] = $group;
        $fields[$name] = $def;
    }
}
echo "Loaded schema v{$schema['version']}: " . count($fields) . " fields in " . count($schema['groups']) . " groups\n";

/* ---------- helpers ---------- */

function sqlType(array $d): string {
    return match ($d['type']) {
        'bool'       => 'TINYINT(1)',
        'int'        => 'INT',
        'decimal'    => 'DECIMAL(3,1)',
        'enum'       => "ENUM('" . implode("','", $d['values']) . "')",
        'string'     => 'VARCHAR(' . ($d['max_len'] ?? 255) . ')',
        'yearmonth'  => 'VARCHAR(7)',
        'datetime'   => 'DATETIME',
        'text', 'json_array' => isset($d['max_len']) && $d['max_len'] > 16000 ? 'MEDIUMTEXT' : 'TEXT',
        default      => throw new RuntimeException("Unknown type {$d['type']}"),
    };
}

function specPlaceholder(string $name, array $d): mixed {
    if (isset($d['null_when']) || !empty($d['nullable'])) {
        return in_array($d['type'], ['bool', 'int', 'decimal'], true) ? null : '';
    }
    return match ($d['type']) {
        'bool'       => false,
        'int'        => 0,
        'decimal'    => 0.0,
        'enum'       => implode('|', $d['values']),
        'yearmonth'  => 'YYYY-MM',
        'json_array' => [],
        default      => $d['note'] ?? '',
    };
}

/* ---------- 1. DDL ---------- */

$cols = ["  `business_id` INT UNSIGNED NOT NULL PRIMARY KEY,"];
foreach ($fields as $name => $d) {
    $null = (!empty($d['nullable']) || isset($d['null_when']) || empty($d['required'])) ? 'NULL' : 'NOT NULL';
    $comment = addslashes(trim(($d['note'] ?? '')));
    $cols[] = "  `{$name}` " . sqlType($d) . " {$null}" . ($comment !== '' ? " COMMENT '{$comment}'" : '') . ',';
}
$ddl = "-- GENERATED by bin/codegen.php from schema/business.schema.json v{$schema['version']} - DO NOT EDIT\n"
     . "CREATE TABLE IF NOT EXISTS `business_profile` (\n"
     . implode("\n", $cols) . "\n"
     . "  `updated_at` TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,\n"
     . "  CONSTRAINT `fk_profile_business` FOREIGN KEY (`business_id`) REFERENCES `businesses`(`id`) ON DELETE CASCADE\n"
     . ") ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;\n";
file_put_contents($root . '/migrations/002_business_profile.sql', $ddl);
echo "✓ migrations/002_business_profile.sql\n";

/* ---------- 2. Research spec (prompt JSON skeleton) ---------- */

$spec = [
    'business_id' => 0,
    'raw_name'    => 'Exact business name',
    'city'        => 'City Name',
    'found_via'   => 'where verified',
    'confidence'  => 'high|medium',
    'email'       => '',
    'phone'       => '',
    'website_url' => 'NEVER guess or construct; empty string beats a guess',
];
foreach ($fields as $name => $d) {
    if (!empty($d['system'])) continue; // verification fields are not asked of the LLM
    $spec[$name] = specPlaceholder($name, $d);
}
file_put_contents(
    $root . '/generated/research_spec.json',
    json_encode(['research_results' => [$spec]], JSON_PRETTY_PRINT | JSON_UNESCAPED_SLASHES) . "\n"
);
echo "✓ generated/research_spec.json (inject into prompts as {research_spec})\n";

/* ---------- 3. Validator ---------- */

$v  = "<?php\ndeclare(strict_types=1);\n";
$v .= "// GENERATED by bin/codegen.php - DO NOT EDIT. Edit schema/business.schema.json and regenerate.\n";
$v .= "namespace HoV2\\Import;\n\nfinal class Validator\n{\n";
$v .= "    /** @return array{0: array<string,mixed>, 1: string[]} [clean row, rejection reasons (non-empty = reject record)] */\n";
$v .= "    public static function validate(array \$in): array\n    {\n";
$v .= "        \$out = []; \$reject = [];\n";
$v .= "        \$hasWebsite = (bool)(\$in['has_website'] ?? false);\n";
$v .= "        if ((bool)(\$in['is_franchise'] ?? false)) { \$reject[] = 'franchise: auto-excluded'; }\n";
$v .= "        if ((\$in['website_confidence'] ?? '') === 'low') { \$in['website_url'] = ''; }\n";
foreach ($fields as $name => $d) {
    if (!empty($d['system'])) continue;
    $v .= "        // {$name} ({$d['type']})\n";
    if (isset($d['null_when'])) {
        $v .= "        \$out['{$name}'] = !\$hasWebsite ? null : (isset(\$in['{$name}']) ? (bool)\$in['{$name}'] : null);\n";
        continue;
    }
    switch ($d['type']) {
        case 'bool':
            $v .= !empty($d['nullable'])
                ? "        \$out['{$name}'] = isset(\$in['{$name}']) ? (bool)\$in['{$name}'] : null;\n"
                : "        \$out['{$name}'] = (bool)(\$in['{$name}'] ?? false);\n";
            break;
        case 'int':
            $min = isset($d['min']) ? "max({$d['min']}, " : '(';
            $v .= !empty($d['nullable'])
                ? "        \$out['{$name}'] = isset(\$in['{$name}']) && \$in['{$name}'] !== '' ? {$min}(int)\$in['{$name}']) : null;\n"
                : "        \$out['{$name}'] = {$min}(int)(\$in['{$name}'] ?? 0));\n";
            break;
        case 'decimal':
            $lo = sprintf('%.1f', $d['min'] ?? 0.0); $hi = sprintf('%.1f', $d['max'] ?? 5.0);
            $v .= !empty($d['nullable'])
                ? "        \$out['{$name}'] = isset(\$in['{$name}']) && \$in['{$name}'] !== '' ? min({$hi}, max({$lo}, (float)\$in['{$name}'])) : null;\n"
                : "        \$out['{$name}'] = min({$hi}, max({$lo}, (float)(\$in['{$name}'] ?? 0)));\n";
            break;
        case 'enum':
            $vals = "['" . implode("','", $d['values']) . "']";
            $fallback = $d['values'][0];
            $v .= "        \$out['{$name}'] = in_array((\$in['{$name}'] ?? ''), {$vals}, true) ? \$in['{$name}'] : " . (!empty($d['nullable']) ? 'null' : "'{$fallback}'") . ";\n";
            break;
        case 'yearmonth':
            $v .= "        \$out['{$name}'] = preg_match('/^\\d{4}-\\d{2}\$/', (string)(\$in['{$name}'] ?? '')) ? \$in['{$name}'] : null;\n";
            break;
        case 'json_array':
            $v .= "        \$out['{$name}'] = json_encode(array_values(array_filter((array)(\$in['{$name}'] ?? []), 'is_string')), JSON_UNESCAPED_SLASHES);\n";
            break;
        default: // string, text
            $max = $d['max_len'] ?? ($d['type'] === 'text' ? 65000 : 255);
            $v .= "        \$out['{$name}'] = mb_substr(trim((string)(\$in['{$name}'] ?? '')), 0, {$max});\n";
            if (isset($d['max_words'])) {
                $v .= "        if (str_word_count(\$out['{$name}']) > {$d['max_words']}) { \$out['{$name}'] = ''; } // over word cap = drop, never trim a verbatim quote\n";
            }
    }
}
$v .= "        return [\$out, \$reject];\n    }\n\n";
$v .= "    /** @return string[] every schema field name, in order */\n";
$v .= "    public const FIELDS = ['" . implode("','", array_keys(array_filter($fields, fn($d) => empty($d['system'])))) . "'];\n";
$v .= "}\n";
file_put_contents($root . '/src/Import/Validator.php', $v);
echo "✓ src/Import/Validator.php\n";

/* ---------- 4. Business domain class ---------- */

$b  = "<?php\ndeclare(strict_types=1);\n";
$b .= "// GENERATED by bin/codegen.php - DO NOT EDIT. Edit schema/business.schema.json and regenerate.\n";
$b .= "namespace HoV2\\Domain;\n\n";
$b .= "/**\n * The canonical Business object. The ONLY shape data takes inside HO v2.\n * Renderers, scorers, and gap detection consume this and nothing else.\n */\n";
$b .= "final class Business\n{\n";
$b .= "    public function __construct(\n";
$b .= "        public readonly int \$id,\n";
$b .= "        public readonly string \$uid,\n";
$b .= "        public readonly string \$slug,\n";
