$b .= "        public readonly string \$category,\n";
$b .= "        public readonly string \$city,\n";
$b .= "        public readonly string \$state,\n";
$b .= "        public readonly string \$pipelineStatus,\n";
$b .= "        public readonly ?string \$email,\n";
$b .= "        public readonly ?string \$phone,\n";
$b .= "        public readonly ?string \$websiteUrl,\n";
$b .= "        public readonly ?string \$facebookUrl,\n";
$b .= "        public readonly ?string \$ownerFirstName,\n";
$b .= "        /** @var array<string,mixed> validated business_profile row */\n";
$b .= "        private readonly array \$profile,\n";
$b .= "    ) {}\n\n";
$b .= "    public function get(string \$field): mixed\n    {\n";
$b .= "        if (!array_key_exists(\$field, \$this->profile)) { throw new \\InvalidArgumentException(\"Unknown profile field: {\$field}\"); }\n";
$b .= "        return \$this->profile[\$field];\n    }\n\n";
$b .= "    public function isVerified(): bool { return \$this->profile['verified_at'] !== null; }\n\n";
foreach ($fields as $name => $d) {
    if (!empty($d['system'])) continue;
    $method = lcfirst(str_replace(' ', '', ucwords(str_replace('_', ' ', $name))));
    $ret = match ($d['type']) {
        'bool'              => '?bool',
        'int'               => '?int',
        'decimal'           => '?float',
        'json_array'        => 'array',
        default             => '?string',
    };
    $body = $d['type'] === 'json_array'
        ? "return json_decode((string)(\$this->profile['{$name}'] ?? '[]'), true) ?: [];"
        : "return \$this->profile['{$name}'] ?? null;";
    $b .= "    public function {$method}(): {$ret} { {$body} }\n";
}
$b .= "}\n";
file_put_contents($root . '/src/Domain/Business.php', $b);
echo "✓ src/Domain/Business.php\n";

echo "\nCodegen complete. Schema is law.\n";
